import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"developer/architecture.md","filePath":"developer/architecture.md","lastUpdated":null}'),n={name:"developer/architecture.md"};function s(i,e,d,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Autofac is a layered .NET control plane around governed agent execution.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Trigger</span></span>
<span class="line"><span>  -&gt; BPMN workflow run</span></span>
<span class="line"><span>      -&gt; agent task -&gt; Agent Orchestrator -&gt; model</span></span>
<span class="line"><span>                              -&gt; Tool Gateway -&gt; policy -&gt; connector or sandbox</span></span>
<span class="line"><span>      -&gt; approval task -&gt; human decision</span></span>
<span class="line"><span>      -&gt; wait state -&gt; timer or external event</span></span>
<span class="line"><span>  -&gt; evidence pack</span></span></code></pre></div><h2 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Project</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>Autofac.Api</code></td><td>API host for workflows, runs, approvals, artifacts, evidence, health, and webhooks.</td></tr><tr><td><code>Autofac.Application</code></td><td>Application use cases, run orchestration contracts, evidence builder, run context.</td></tr><tr><td><code>Autofac.Domain</code></td><td>Core entities and runtime contracts.</td></tr><tr><td><code>Autofac.Workflows</code></td><td>BPMN validator and in-process workflow engine.</td></tr><tr><td><code>Autofac.Agents</code></td><td>Agent orchestrator, model clients, Tool Gateway, Hook Gateway, skills, prompt assembler.</td></tr><tr><td><code>Autofac.AgentSecOps</code></td><td>Policy evaluation and action governance.</td></tr><tr><td><code>Autofac.Sandboxes</code></td><td>Docker, OpenSandbox, and Kubernetes sandbox providers.</td></tr><tr><td><code>Autofac.Integrations</code></td><td>External connectors such as GitHub and CI/CD.</td></tr><tr><td><code>Autofac.Storage</code></td><td>Artifact and blob storage abstractions.</td></tr><tr><td><code>Autofac.Observability</code></td><td>Logging, metrics, and tracing setup.</td></tr><tr><td><code>Autofac.Infrastructure</code></td><td>EF Core/Postgres persistence, outbox, dispatch worker.</td></tr><tr><td><code>Autofac.AgentRunner</code></td><td>In-sandbox runner image entrypoint.</td></tr></tbody></table><h2 id="workflow-runtime" tabindex="-1">Workflow runtime <a class="header-anchor" href="#workflow-runtime" aria-label="Permalink to &quot;Workflow runtime&quot;">​</a></h2><p><code>WorkflowRuntime:Mode=Autofac</code> is the default. It uses a bounded Postgres-backed in-process engine with durable checkpoints and asynchronous dispatch through a transactional outbox.</p><p><code>WorkflowRuntime:Mode=Camunda</code> is an opt-in enterprise adapter. Camunda settings should not be consumed when the Autofac runtime is active.</p><h2 id="agent-layer" tabindex="-1">Agent layer <a class="header-anchor" href="#agent-layer" aria-label="Permalink to &quot;Agent layer&quot;">​</a></h2><p>The agent layer selects an <code>ILanguageModelClient</code>, assembles prompts from agent profile, task prompt, skills, and run context, and enforces model budgets. Tool requests from the model do not execute directly. They go through the Tool Gateway.</p><p>Agent capabilities include:</p><ul><li>Knowledge retrieval with citations.</li><li>Run-scoped agent messages.</li><li>Inline agent delegation through <code>agent.request</code>.</li><li>Blocking human questions through <code>human.ask</code>.</li><li>Non-blocking human notifications.</li></ul><h2 id="governance-layer" tabindex="-1">Governance layer <a class="header-anchor" href="#governance-layer" aria-label="Permalink to &quot;Governance layer&quot;">​</a></h2><p>The Tool Gateway checks:</p><ul><li>agent permission level</li><li>allowed and denied tools</li><li>policy rules</li><li>purpose and risk</li><li>sandbox/profile boundaries</li></ul><p>Policy decisions are recorded with rationale and risk factors. Human approval gates add explicit decisions to the workflow state.</p><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>Postgres stores workflows, runs, steps, events, run context, approvals, agent interactions, outbox state, and related metadata. Artifact bytes live in the configured storage provider.</p><p>See <a href="/reference/persistence-schema.html">Persistence Schema</a> for table-level details.</p><h2 id="web-ui" tabindex="-1">Web UI <a class="header-anchor" href="#web-ui" aria-label="Permalink to &quot;Web UI&quot;">​</a></h2><p>The web UI is a React/Vite application that provides:</p><ul><li>workflow designer</li><li>run board</li><li>run detail with BPMN status</li><li>approvals</li><li>settings</li><li>agent and skill authoring surfaces</li></ul><p>The UI calls the API; it does not bypass product policy.</p>`,23)])])}const g=t(n,[["render",s]]);export{h as __pageData,g as default};
